import React, { Component } from 'react';
import { Link } from 'react-router-dom';
import Table from '../Table';
import './style.css';

const POSTS_COLUMNS = [
  {
    accessor: 'id',
    Header: 'ID',
  },
  {
    accessor: 'title',
    Header: 'Title',
  },
  {
    accessor: 'tag',
    Header: 'Tag',
  },
  {
    accessor: 'body',
    Header: 'Body',
  },
  {
    accessor: 'action',
    Header: 'Action',
  },
];

class PostsPage extends Component {
  state = {
    posts: [],
    isLoading: true,
  };

  componentDidMount() {
    fetch('https://jsonplaceholder.typicode.com/posts?_limit=12')
      .then((response) => response.json())
      .then((posts) => {
        const normalizedPosts = posts.map((post) => ({
          ...post,
          tag: `User ${post.userId}`,
        }));

        this.setState({
          posts: normalizedPosts,
          isLoading: false,
        });
      })
      .catch(() => {
        this.setState({
          posts: [],
          isLoading: false,
        });
      });
  }

  render() {
    const tableData = this.state.posts.map((post) => ({
      ...post,
      action: (
        <Link to={`/posts/${post.id}`} className="post-table-link">
          Read More
        </Link>
      ),
    }));

    return (
      <main className="posts-page">
        <section className="posts-hero">
          <div className="posts-intro">
            <p className="posts-kicker">Posts</p>
            <h1>Notes, ideas, and practice content from your React workspace.</h1>
            <p className="posts-description">
              This page now loads posts from a real API and keeps the same clean table
              structure for browsing and opening details.
            </p>
            <div className="posts-metrics">
              <div className="metric-card">
                <strong>{this.state.posts.length}</strong>
                <span>Available Posts</span>
              </div>
              <div className="metric-card">
                <strong>React</strong>
                <span>Main Topic</span>
              </div>
              <div className="metric-card">
                <strong>UI</strong>
                <span>Focus Area</span>
              </div>
            </div>
          </div>

          <aside className="posts-side-card">
            <p className="posts-side-label">Editor Note</p>
            <h2>Live data is now part of the flow.</h2>
            <p>
              The table uses API content, while `Read More` opens a post details page
              with the same source.
            </p>
          </aside>
        </section>

        <section className="posts-table-section">
          <Table columns={POSTS_COLUMNS} data={tableData} isLoading={this.state.isLoading} />
        </section>
      </main>
    );
  }
}

export default PostsPage;
